SELECT emission_date, emission_value
FROM carbon_emissions
WHERE emission_value > 10;

SELECT date, baseline, type_id
FROM energy_data
WHERE baseline > 1000;

SELECT MAX(trend_value) 
FROM energy_trends 
WHERE energy_data_id = '1';

SELECT 
  (SELECT AVG(region_energy_value) 
   FROM regions_energy_data 
   WHERE region_id = (SELECT region_id FROM regions WHERE population = (SELECT MAX(population) FROM regions))
  ) AS Avg_Energy_Most_Populous,

  (SELECT region_name 
   FROM regions 
   WHERE region_id = (SELECT region_id FROM carbon_emissions WHERE emission_value = (SELECT MAX(emission_value) FROM carbon_emissions))
  ) AS Highest_Emission_Region;

SELECT UPPER(type_name) 
FROM energy_types 
WHERE type_name LIKE 'EPDM%';

SELECT region_id, 'Overshooting' AS status
FROM regions
WHERE average_temperature > (SELECT AVG(average_temperature) FROM regions);

SELECT r.region_name, ce.emission_date
FROM regions r
JOIN carbon_emissions ce ON r.region_id = ce.region_id;
